SELECT MSG.CO_ID, MSG.MSG_ID, MSG.DFLT_MSG_VAL, MSG.MDL_NM, MSG.MSG_TP_VAL, MSG.CRE_DT, MSG.CRE_USR_ID, MSG.UPD_DT, MSG.UPD_USR_ID FROM COM_MSG MSG WHERE 1=1 AND MSG.CO_ID = #{coId}
AND MSG.MSG_ID ILIKE '%' || #{msgId} || '%'
AND MSG.DFLT_MSG_VAL ILIKE '%' || #{dfltMsgVal} || '%'
AND MSG.MDL_NM = #{mdlNm}
AND MSG.MSG_TP_VAL = #{msgTpVal}
ORDER BY ${sort.sortField} ${sort.sortType}, MSG.UPD_DT DESC
ORDER BY MSG.UPD_DT DESC
LIMIT #{pagination.pageSize} OFFSET (#{pagination.current} - 1) * #{pagination.pageSize}

SELECT COUNT(*)
FROM COM_MSG MSG
WHERE 1=1
    AND MSG.CO_ID = #{coId}

    AND MSG.MSG_ID ILIKE '%' || #{msgId} || '%'


    AND MSG.DFLT_MSG_VAL ILIKE '%' || #{dfltMsgVal} || '%'


    AND MSG.MDL_NM = #{mdlNm}


    AND MSG.MSG_TP_VAL = #{msgTpVal}

SELECT COUNT(*)
FROM COM_MSG MSG
WHERE MSG.CO_ID = #{coId}
    AND MSG.DFLT_MSG_VAL = #{dfltMsgVal}

    AND MSG.MSG_ID != #{msgId}

