mapper.select:
        SELECT 
            MSG.CO_ID,
            MSG.MSG_ID,
            COALESCE(TRANS.TRANS_MSG_VAL, MSG.DFLT_MSG_VAL) AS DFLT_MSG_VAL
        FROM COM_MSG MSG LEFT JOIN COM_MSG_TRANS TRANS ON (
			MSG.CO_ID = TRANS.CO_ID
			AND MSG.MSG_ID = TRANS.MSG_ID
		)
        WHERE MSG.CO_ID = #{coId}

            AND TRANS.LANG_VAL = #{langVal}
